/* selectMrscmaList */ select CONCAT(A.COMPKEY, A.WAREKEY, A.DOCCATE, A.DOCTYPE, A.RSNCODE) AS ROWKEY , A.COMPKEY , A.WAREKEY, (select C.WHNAMLC from MWARMA C where A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY ) as COMCDTX , A.DOCCATE, B.DOCCTNM , A.DOCCATE as DOCCTCD , A.DOCTYPE, B.DOCTYNM , A.DOCTYPE as DOCTYCD , A.RSNCODE, A.RSNCDNM , A.RSNCDOD , A.RSCATE1, A.RSCATE2, A.RSCATE3 , A.RSATTR1, A.RSATTR2, A.RSATTR3 , A.RSUSEYN , FN_COM_TODATE(A.CREDATE) as CREDATE, FN_COM_TOTIME(A.CRETIME) as CRETIME, fn_sy_usernam(A.COMPKEY, A.CREUSER) as CREUSER , FN_COM_TODATE(A.LMODATE) as LMODATE, FN_COM_TOTIME(A.LMOTIME) as LMOTIME, fn_sy_usernam(A.COMPKEY, A.LMOUSER) as LMOUSER from MRSCMA A inner join MDOCMA B on A.COMPKEY = B.COMPKEY and A.WAREKEY = B.WAREKEY and A.DOCCATE = B.DOCCATE and A.DOCTYPE = B.DOCTYPE
A.COMPKEY = #{userData.compkey}
and UPPER(A.WAREKEY) = UPPER(#{warekey})
and UPPER(B.DOCCTNM) like concat('%',#{docctnm},'%')
and UPPER(B.DOCTYNM) like concat('%',#{doctynm},'%')
order by A.COMPKEY, A.WAREKEY, A.DOCCATE, A.DOCTYPE, A.RSNCDOD

