mapper.select:
/* selectMcodem */
select COMCDVL as COMBOVL
, COMCDTX as COMBONM
, COMCDKY
, CDCATE1
, CDCATE2
from V_MCODEM
where COMPKEY = #{userData.compkey}
and ACTYN = 'Y'


		and COUSEYN = #{couseyn}


		and COUSEYN = 'Y'




	and COMCDKY = #{comcdky}


	and COMCDKY in

		#{item}




	and COMCDVL = #{comcdvl}


	and COMCDVL in

		#{item}



	and IFNULL(CDCATE1,'') = #{cdcate1}


	and CDCATE2 = #{cdcate2}


	and CDCATE2 in

		#{item}



	and WAREKEY = #{warekey}


	and COMCDVL != #{mdp3Comcdvl}

order by COMCDOR asc

