/* insertMcodem */
insert into MCODEM
( COMPKEY, COMCDKY, COMCDVL, COMKYTX, WAREKEY
, COMCDTX, COMCDOR, COMCDSY, CDCATE1, CDCATE2
, CDCATE3, CDATTR1, CDATTR2, CDATTR3, COUSEYN
, CREDATE, CRETIME, CREUSER
, LMODATE, LMOTIME, LMOUSER )
values
( #{compkey}, UPPER(#{comcdky}), UPPER(#{comcdvl}), #{comkytx}, #{warekey}
, #{comcdtx}, #{comcdor}, #{comcdsy}, #{cdcate1}, #{cdcate2}
, #{cdcate3}, #{cdattr1}, #{cdattr2}, #{cdattr3}, #{couseyn}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

