mapper.select:
/* selectMlscalList */ select concat(ML.COMPKEY, ML.WAREKEY, ML.STDDATE) as ROWKEY , ML.COMPKEY, ML.WAREKEY, ML.STDDATE , MW.WHNAMLC, ML.LOGYEAR, ML.LOGMONT, ML.LOGDATE, ML.LOGWEEK , ML.WEKNUM7, ML.WEKNUM0, ML.NATHOLI , FN_COM_TODATE(ML.CREDATE) as CREDATE , FN_COM_TOTIME(ML.CRETIME) as CRETIME , fn_sy_usernam(ML.COMPKEY, ML.CREUSER) as CREUSER , FN_COM_TODATE(ML.LMODATE) as LMODATE , FN_COM_TOTIME(ML.LMOTIME) as LMOTIME , fn_sy_usernam(ML.COMPKEY, ML.LMOUSER) as LMOUSER , ML.UPDTCHK from MLSCAL ML inner join MWARMA MW on( ML.COMPKEY = MW.COMPKEY and ML.WAREKEY = MW.WAREKEY) where ML.COMPKEY = #{userData.compkey}
and MW.WAREKEY = #{warekey}
and date_format(ML.STDDATE, '%Y-%m-%d') >= #{startStddate}
and date_format(ML.STDDATE, '%Y-%m-%d') <= #{endStddate}
order by ML.COMPKEY asc, ML.WAREKEY asc, ML.STDDATE desc, MW.WHNAMLC asc

